    flame_proj_batch_T16_d16x32_primitive(Bp_id, WK, Bc_id, oRin, Bc_id, oK);
    flame_proj_batch_T16_d16x32_primitive(Bp_id, WV, Bc_id, oRin, Bc_id, oV);
    Bc = _hx_farr_table[Bc_id].buf;

